import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { FileText, BarChart3, History, Building2, TrendingUp } from "lucide-react";
import { api } from "@/lib/api";
import {
  ResponsiveContainer,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  Cell,
} from "recharts";

const Dashboard = () => {
  const [documents, setDocuments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadDocuments = async () => {
      try {
        const response = await api.get("/documents/");
        setDocuments(response.data || []);
      } catch (err) {
        setError(err?.response?.data?.detail || err.message || "Error al cargar datos");
      } finally {
        setLoading(false);
      }
    };

    loadDocuments();
  }, []);

  const dashboardRows = useMemo(() => {
    const rows = [];

    for (const doc of documents) {
      const data = doc.extracted_data || {};

      if (data.categoria_tipo) {
        rows.push({
          id: doc.id,
          categoria_tipo: data.categoria_tipo,
          categoria_subtipo: data.categoria_subtipo || data.tipo || "GENERAL",
          monto_total: Number(data.monto_total ?? 0),
          subcategoria_label: data.categoria_subtipo || data.tipo || data.proveedor || "GENERAL",
        });
      }

      for (const section of ["ventas_terceros", "telefonia_movil", "rentas_servicios", "resumen_consumo"]) {
        const items = Array.isArray(data[section]) ? data[section] : [];
        for (const item of items) {
          if (item.categoria_tipo) {
            rows.push({
              id: doc.id,
              categoria_tipo: item.categoria_tipo,
              categoria_subtipo: item.categoria_subtipo || item.descripcion || "GENERAL",
              monto_total: Number(item.monto_bs ?? 0),
              subcategoria_label: item.categoria_subtipo || item.descripcion || "GENERAL",
            });
          }
        }
      }
    }

    return rows;
  }, [documents]);

  const totalByCategory = useMemo(() => {
    const totals = {};
    dashboardRows.forEach((row) => {
      if (!row.categoria_tipo) return;
      totals[row.categoria_tipo] = (totals[row.categoria_tipo] || 0) + (row.monto_total || 0);
    });
    return Object.entries(totals).map(([categoria_tipo, monto_total]) => ({ categoria_tipo, monto_total }));
  }, [dashboardRows]);

  const totalBySubcategory = useMemo(() => {
    const totals = {};
    dashboardRows.forEach((row) => {
      if (!row.categoria_tipo || !row.categoria_subtipo) return;
      const key = `${row.categoria_tipo}||${row.categoria_subtipo}`;
      totals[key] = (totals[key] || 0) + (row.monto_total || 0);
    });
    return Object.entries(totals).map(([key, monto_total]) => {
      const [categoria_tipo, categoria_subtipo] = key.split("||");
      return { categoria_tipo, categoria_subtipo, monto_total };
    });
  }, [dashboardRows]);

  const COLORS = ["#0033CC", "#16A34A", "#F59E0B", "#DC2626", "#8B5CF6", "#0EA5E9"];

  const features = [
    {
      title: "Modulo A: Facturacion General",
      description:
        "Extrae datos de facturas: proveedor, RIF, fecha, periodo, subtotal, IVA, monto total, moneda y tipo.",
      icon: FileText,
      link: "/module-a",
      color: "#0033CC",
      testId: "card-module-a",
    },
    {
      title: "Modulo B: Analisis Especializado",
      description:
        "Procesa documentos complejos: ventas de terceros, telefonia movil, rentas y servicios, resumen de consumo.",
      icon: BarChart3,
      link: "/module-b",
      color: "#16A34A",
      testId: "card-module-b",
    },
    {
      title: "Historial de Documentos",
      description:
        "Revisa todos los documentos procesados anteriormente y sus datos extraidos.",
      icon: History,
      link: "/history",
      color: "#EAB308",
      testId: "card-history",
    },
    {
      title: "Centros de Costo",
      description:
        "Gestiona centros de costo y asigna lineas para el analisis detallado.",
      icon: Building2,
      link: "/cost-centers",
      color: "#DC2626",
      testId: "card-cost-centers",
    },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-white border border-zinc-200 rounded-none p-8">
        <div className="flex items-start justify-between">
          <div>
            <h1 className="font-heading text-4xl font-bold text-[#09090B] tracking-tight mb-3">
              Sistema de Extraccion Inteligente de Datos
            </h1>
            <p className="text-lg text-zinc-600 leading-relaxed max-w-3xl">
              Procesa documentos de facturacion y archivos complejos usando Gemini 2.5
              Flash con validaciones previas y un flujo de extraccion consistente.
            </p>
          </div>
          <TrendingUp className="w-16 h-16 text-[#0033CC]" strokeWidth={1.5} />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {features.map((feature) => {
          const Icon = feature.icon;
          return (
            <Link
              key={feature.link}
              to={feature.link}
              data-testid={feature.testId}
              className="bg-white border border-zinc-200 rounded-none p-6 hover:border-[#0033CC] transition-colors group"
            >
              <div className="flex items-start gap-4">
                <div className="p-3 bg-zinc-50 border border-zinc-200">
                  <Icon className="w-6 h-6" style={{ color: feature.color }} strokeWidth={1.5} />
                </div>
                <div className="flex-1">
                  <h3 className="font-heading text-lg font-bold text-[#09090B] mb-2 group-hover:text-[#0033CC] transition-colors">
                    {feature.title}
                  </h3>
                  <p className="text-sm text-zinc-600 leading-relaxed">
                    {feature.description}
                  </p>
                </div>
              </div>
            </Link>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;
